CREATE TABLE capital_investments_5 (
    id SERIAL PRIMARY KEY,
    organization_name VARCHAR(255) NOT NULL,
    organization_code VARCHAR(10),
    total_objects INT,
    total_investments_start NUMERIC(20,1),
    total_investments_report_year NUMERIC(20,1),
    -- Construction continues
    continues_objects INT,
    continues_investments_start NUMERIC(20,1),
    continues_investments_report_year NUMERIC(20,1),
    continues_faip_objects INT,
    continues_faip_investments_start NUMERIC(20,1),
    continues_faip_investments_report_year NUMERIC(20,1),
    -- Temporarily suspended / mothballed
    suspended_objects INT,
    suspended_investments_start NUMERIC(20,1),
    suspended_investments_report_year NUMERIC(20,1),
    -- Permanently discontinued
    discontinued_objects INT,
    discontinued_investments_start NUMERIC(20,1),
    discontinued_investments_report_year NUMERIC(20,1),
    -- Construction not started
    not_started_objects INT,
    not_started_investments_start NUMERIC(20,1),
    not_started_investments_report_year NUMERIC(20,1)
);

